import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/client';
import LoadingSpinner from '../components/LoadingSpinner';
import ToastMessage from '../components/ToastMessage';

function Login() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const { data } = await api.post('/auth/login', form);
      localStorage.setItem('user', JSON.stringify(data));
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container py-5">
      <div className="row justify-content-center">
        <div className="col-md-5">
          <div className="card p-4 shadow-sm">
            <h3 className="mb-3 text-center">Login</h3>
            <form onSubmit={submit}>
              <input className="form-control mb-3" placeholder="Email" type="email"
                value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} />
              <input className="form-control mb-3" placeholder="Password" type="password"
                value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} />
              <button className="btn btn-danger w-100" type="submit" disabled={loading}>Login</button>
            </form>
            {loading && <LoadingSpinner />}
            <ToastMessage message={error} type="danger" />
          </div>
        </div>
      </div>
    </div>
  );
}

export default Login;
